DROP TABLE IF EXISTS `students`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `students` (
  `id` int NOT NULL AUTO_INCREMENT,
  `student_id` varchar(20) COLLATE utf8mb4_general_ci NOT NULL,
  `firstname` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `lastname` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `othername` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `class_id` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `stream_id` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `DOB` date DEFAULT NULL,
  `gender` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `section` varchar(10) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `district` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `subcounty` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `parish` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `village` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `marital_status` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `contact` varchar(15) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `academic_status` varchar(15) COLLATE utf8mb4_general_ci DEFAULT 'inactive',
  `photo_passport` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `photo_full` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `guardian_id` int DEFAULT NULL,
  `sibling_id` int DEFAULT NULL,
  `nin` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `joindate` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `religion` varchar(50) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `student_id` (`student_id`)
) ENGINE=InnoDB AUTO_INCREMENT=364 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

